def magic_square_test(square):
    n = len(square)
    if n == 0:
        return False

    # Calculate the sum of the first row to use as a reference
    magic_sum = sum(square[0])

    # Check sums of rows
    for row in square:
        if sum(row) != magic_sum:
            return False

    # Check sums of columns
    for col in range(n):
        if sum(square[row][col] for row in range(n)) != magic_sum:
            return False

    # Check sum of main diagonal
    if sum(square[i][i] for i in range(n)) != magic_sum:
        return False

    # Check sum of secondary diagonal
    if sum(square[i][n-1-i] for i in range(n)) != magic_sum:
        return False

    return True

