def longest_subseq_with_diff_one(arr):
    n = len(arr)
    if n == 0:
        return 0

    # Initialize the list to store the length of the longest subsequence ending at each index
    dp = [1] * n

    # Compute the longest subsequence for each element
    for i in range(1, n):
        for j in range(i):
            if abs(arr[i] - arr[j]) == 1:
                dp[i] = max(dp[i], dp[j] + 1)

    # The result is the maximum value in dp array
    return max(dp)
