    # Find the maximum element in the array
    max_element = max(arr)

    # Calculate the total number of operations required
    total_ops = 0
    for i in range(n):
        if arr[i] < max_element:
            total_ops += (max_element - arr[i])

    # Since each operation increases one element by k, we need to divide the total ops by k
    return total_ops // k

