    i = 2
    while i * i <= n:
        if n % i:
            i += 1
        else:
            # If divisors are equal, add it only once
            if i * (n // i) == n:
                sum_div += i
            else:
                # Add both divisors
                sum_div += i + (n // i)
            i += 1

